    constructor(args?: {
        client?: Client;
        key?: string;
    }) {
        super(args);
        Api.__registry.set(this, args?.key);
    }
    
    private _authors?: Authors;
    get authors(): Authors {
        return this._authors ??= new Authors({ client: this.client });
    }
    
    private _library?: Library;
    get library(): Library {
        return this._library ??= new Library({ client: this.client });
    }
    
    private _mempool?: Mempool;
